#!/usr/bin/env python3
"""
validate-sketch-recall.py — Phase A4 of the Standing-Wave Mesh rollout.

Given a `<model>-sketches.knot` artifact (produced by
`encode-real-model.py --with-exclusion-sketch RANK`) and a HuggingFace
causal-LM id, measure recall@K of sketch-reconstructed lm_head top-K vs.
the dense lm_head top-1, across N hidden states sampled from real prompt
forward passes.

Pass criterion (per docs/STANDING_WAVE_MESH_TODO.md):
  * recall@50  ≥ 10%
  * recall@100 ≥ 15%

If recall is much lower than that, the sketch encoding is broken — surface
empirically *before* cobordism / registry / layer-worker work depends on it.

Usage:
    python3 validate-sketch-recall.py \\
        --sketches rknots/qwen-0.5b-sketches.knot \\
        --model Qwen/Qwen2.5-0.5B-Instruct \\
        [--prompts-file prompts.txt] [--max-positions 100] [--out report.md]

Defaults to the same eight prompts as validate-lm-head-router.py so results
are comparable to the original GKQ rank-K router experiment.
"""

from __future__ import annotations

import argparse
import os
import sys
import time
from pathlib import Path
from typing import Dict, List, Tuple

import numpy as np

_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import sketch_knot_format as skf  # noqa: E402

DEFAULT_PROMPTS: List[str] = [
    "What is the capital of France?",
    "def fibonacci(n):\n    if n < 2:\n        return n\n    return ",
    "Hello, how are you doing today? I was thinking about",
    "The mitochondria is the powerhouse of the",
    "Translate to Spanish: Good morning, my friend. Spanish:",
    "1 + 1 = 2. 2 + 2 = 4. 3 + 3 = ",
    "Once upon a time in a distant kingdom, there lived a",
    "import numpy as np\narr = np.zeros((3, 4))\nprint(arr.",
]

DEFAULT_KS: List[int] = [1, 5, 10, 25, 50, 100, 200]
LM_HEAD_SKETCH_CANDIDATES: Tuple[str, ...] = ("output.weight", "token_embd.weight")
PASS_RECALL_AT_50: float = 0.10
PASS_RECALL_AT_100: float = 0.15


# ─────────────────────────────────────────────────────────────────────────────
# HELPERS
# ─────────────────────────────────────────────────────────────────────────────


def find_lm_head_sketch(sketches: Dict[str, skf.SketchEntry]) -> skf.SketchEntry:
    """Pick the sketch we'll use as the lm_head router.

    Prefers `output.weight` (the canonical lm_head name in the GKQ scheme);
    falls back to `token_embd.weight` if the model has tied embeddings and
    only that name was sketched.
    """
    for name in LM_HEAD_SKETCH_CANDIDATES:
        if name in sketches:
            return sketches[name]
    raise KeyError(
        f"No lm_head sketch in artifact (looked for {LM_HEAD_SKETCH_CANDIDATES!r}); "
        f"available: {sorted(sketches.keys())[:8]}…"
    )


def collect_hidden_states(model, tokenizer, prompts: List[str], max_positions: int) \
        -> Tuple[np.ndarray, np.ndarray]:
    """Run dense forward passes and gather (hidden, true_top1) at every
    position, up to `max_positions` total positions."""
    import torch

    hidden_list: List[np.ndarray] = []
    top1_list: List[int] = []
    seen = 0
    with torch.no_grad():
        for prompt in prompts:
            if seen >= max_positions:
                break
            ids = tokenizer(prompt, return_tensors="pt").input_ids
            out = model(ids, output_hidden_states=True, use_cache=False)
            h = out.hidden_states[-1].squeeze(0).cpu().numpy().astype(np.float32)  # [seq, hidden]
            logits = out.logits.squeeze(0).cpu().numpy().astype(np.float32)        # [seq, vocab]
            top1 = logits.argmax(axis=-1)
            take = min(h.shape[0], max_positions - seen)
            hidden_list.append(h[:take])
            top1_list.extend(top1[:take].tolist())
            seen += take
    H = np.concatenate(hidden_list, axis=0).astype(np.float32)
    T = np.asarray(top1_list, dtype=np.int64)
    return H, T


def eval_recall(H: np.ndarray, true_top1: np.ndarray, W_approx: np.ndarray,
                ks: List[int]) -> Dict[int, float]:
    """Recall@K = fraction of positions whose dense top-1 is in the
    sketch-reconstructed top-K candidate set."""
    logits = H @ W_approx.T  # [N, vocab]
    max_k = min(max(ks), logits.shape[1])
    part = np.argpartition(-logits, kth=max_k - 1, axis=-1)[:, :max_k]
    row_idx = np.arange(part.shape[0])[:, None]
    sorted_top = part[row_idx, np.argsort(-logits[row_idx, part], axis=-1)]
    out: Dict[int, float] = {}
    for k in ks:
        kk = min(k, max_k)
        topk = sorted_top[:, :kk]
        hits = np.any(topk == true_top1[:, None], axis=-1)
        out[k] = float(hits.mean())
    return out


def format_recall_table(name: str, recall: Dict[int, float]) -> str:
    ks = sorted(recall.keys())
    header = "| metric | " + " | ".join(f"@{k}" for k in ks) + " |"
    sep    = "|---" * (len(ks) + 1) + "|"
    row    = f"| {name} | " + " | ".join(f"{recall[k]*100:5.2f}%" for k in ks) + " |"
    return "\n".join([header, sep, row])


# ─────────────────────────────────────────────────────────────────────────────
# MAIN
# ─────────────────────────────────────────────────────────────────────────────


def main(argv=None) -> int:
    p = argparse.ArgumentParser(description="Validate sketch recall@K against dense lm_head top-1")
    p.add_argument("--sketches", required=True, help="Path to <model>-sketches.knot")
    p.add_argument("--model", required=True, help="HuggingFace model id")
    p.add_argument("--prompts-file", default=None,
                   help="Optional file with one prompt per line (else: 8 builtin prompts)")
    p.add_argument("--max-positions", type=int, default=80,
                   help="Cap on hidden-state positions evaluated (default 80)")
    p.add_argument("--ks", type=int, nargs="+", default=DEFAULT_KS,
                   help=f"K values for recall@K (default: {DEFAULT_KS})")
    p.add_argument("--out", default=None,
                   help="Write a markdown report to this path (default: print only)")
    p.add_argument("--limit-vocab", type=int, default=None,
                   help="Cap vocab size for the recall computation (debug: keep RAM bounded)")
    args = p.parse_args(argv)

    sketch_path = Path(args.sketches)
    if not sketch_path.exists():
        print(f"ERROR: sketches file not found: {sketch_path}", file=sys.stderr)
        return 2

    print(f"[load] sketch artifact: {sketch_path}")
    sketches_pkg = skf.read_sketches_knot(str(sketch_path))
    sketches = sketches_pkg["sketches"]
    meta = sketches_pkg["metadata"]
    print(f"[load] sketches: {len(sketches)} entries, "
          f"sketch_rank_default={meta.get('sketch_rank_default')}, "
          f"file={sketch_path.stat().st_size/1e6:.2f} MB")

    lm_sketch = find_lm_head_sketch(sketches)
    print(f"[lm_head] using sketch: {lm_sketch.name}  "
          f"d_out={lm_sketch.d_out} d_in={lm_sketch.d_in} rank={lm_sketch.rank}")

    # ── load the model ─────────────────────────────────────────────────────
    try:
        import torch
        from transformers import AutoModelForCausalLM, AutoTokenizer
    except Exception as e:
        print(f"ERROR: transformers/torch not installed: {e}", file=sys.stderr)
        return 2

    print(f"[hf] loading {args.model} (cpu, float32)…")
    t0 = time.time()
    tokenizer = AutoTokenizer.from_pretrained(args.model)
    model = AutoModelForCausalLM.from_pretrained(
        args.model, torch_dtype=torch.float32, device_map="cpu", low_cpu_mem_usage=True
    )
    model.eval()
    print(f"[hf] loaded in {time.time()-t0:.1f}s")

    # ── collect hidden states + true top-1 ─────────────────────────────────
    if args.prompts_file:
        prompts = [ln.strip() for ln in Path(args.prompts_file).read_text().splitlines() if ln.strip()]
    else:
        prompts = DEFAULT_PROMPTS
    print(f"[hidden] {len(prompts)} prompts, cap {args.max_positions} positions")
    t0 = time.time()
    H, true_top1 = collect_hidden_states(model, tokenizer, prompts, args.max_positions)
    print(f"[hidden] {H.shape[0]} positions, hidden_dim={H.shape[1]}, "
          f"collected in {time.time()-t0:.1f}s")

    # Free HF model — only need (H, true_top1) and the sketch.
    del model
    import gc; gc.collect()

    # ── reconstruct lm_head from sketch and evaluate ───────────────────────
    print(f"[recall] dequantizing rank-{lm_sketch.rank} sketch "
          f"({lm_sketch.d_out}×{lm_sketch.d_in})…")
    t0 = time.time()
    W_approx = skf.reconstruct_sketch(
        lm_sketch.u_q8, lm_sketch.sigma_q8, lm_sketch.v_q8,
        lm_sketch.u_max, lm_sketch.sigma_max, lm_sketch.v_max,
    )
    print(f"[recall] reconstruction: shape={W_approx.shape} in {time.time()-t0:.1f}s")
    if args.limit_vocab is not None and W_approx.shape[0] > args.limit_vocab:
        # Diagnostic: truncate vocab. Hidden states still hit true tokens that
        # may be outside this slice; those count as misses.
        W_approx = W_approx[: args.limit_vocab]

    if H.shape[1] != W_approx.shape[1]:
        print(f"ERROR: hidden_dim {H.shape[1]} != sketch d_in {W_approx.shape[1]}; "
              f"are sketch and model the same architecture?", file=sys.stderr)
        return 3

    t0 = time.time()
    recall = eval_recall(H, true_top1, W_approx, args.ks)
    print(f"[recall] computed in {time.time()-t0:.1f}s")

    table = format_recall_table(f"recall (sketch rank-{lm_sketch.rank})", recall)
    print()
    print(table)
    print()

    # ── pass/fail verdict ──────────────────────────────────────────────────
    r50 = recall.get(50, 0.0)
    r100 = recall.get(100, 0.0)
    pass_50 = r50 >= PASS_RECALL_AT_50
    pass_100 = r100 >= PASS_RECALL_AT_100
    verdict_lines: List[str] = []
    verdict_lines.append(
        f"recall@50  = {r50*100:5.2f}%  (need ≥{PASS_RECALL_AT_50*100:.0f}%)  "
        + ("PASS" if pass_50 else "FAIL")
    )
    verdict_lines.append(
        f"recall@100 = {r100*100:5.2f}%  (need ≥{PASS_RECALL_AT_100*100:.0f}%)  "
        + ("PASS" if pass_100 else "FAIL")
    )
    overall_pass = pass_50 and pass_100
    for line in verdict_lines:
        print(line)
    print()
    print("verdict:", "PASS" if overall_pass else "FAIL")

    if args.out:
        out_path = Path(args.out)
        out_path.parent.mkdir(parents=True, exist_ok=True)
        body = [
            f"# Sketch recall@K — {args.model}\n",
            f"- sketches: `{sketch_path}` ({sketch_path.stat().st_size/1e6:.2f} MB)",
            f"- sketch rank: {lm_sketch.rank}",
            f"- lm_head sketch tensor: `{lm_sketch.name}`",
            f"- positions evaluated: {H.shape[0]}  (prompts: {len(prompts)})",
            f"- vocab: {W_approx.shape[0]}, hidden: {H.shape[1]}\n",
            "## Recall\n",
            table,
            "\n## Pass / fail\n",
            "\n".join(f"- {ln}" for ln in verdict_lines),
            f"\n**Overall: {'PASS' if overall_pass else 'FAIL'}**\n",
        ]
        out_path.write_text("\n".join(body))
        print(f"[out] wrote {out_path}")

    return 0 if overall_pass else 1


if __name__ == "__main__":
    os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
    os.environ.setdefault("OMP_NUM_THREADS", "1")
    raise SystemExit(main())
